import { useEffect, useRef, useState } from "react";
import "./GlobalSearch.css";

export default function GlobalSearch() {
    const [query, setQuery] = useState("");
    const [results, setResults] = useState(null);
    const [open, setOpen] = useState(false);
    const boxRef = useRef(null);

    useEffect(() => {
        if (!query.trim()) {
            setResults(null);
            return;
        }

        const controller = new AbortController();

        fetch(`/api/search?q=${encodeURIComponent(query)}`, {
            signal: controller.signal,
        })
            .then(r => r.json())
            .then(setResults)
            .catch(() => {});

        return () => controller.abort();
    }, [query]);

    useEffect(() => {
        const handler = e => {
            if (!boxRef.current?.contains(e.target)) setOpen(false);
        };
        document.addEventListener("mousedown", handler);
        return () => document.removeEventListener("mousedown", handler);
    }, []);

    return (
        <div className="global-search" ref={boxRef}>
            <input
                type="text"
                placeholder="Search"
                value={query}
                onFocus={() => setOpen(true)}
                onChange={e => setQuery(e.target.value)}
            />

            {open && results && (
                <SearchDropdown results={results} />
            )}
        </div>
    );
}

function SearchDropdown({ results }) {
    return (
        <div className="search-dropdown">
            <SearchSection title="Events" items={results.events} />
            <SearchSection title="Clubs" items={results.clubs} />
            <SearchSection title="Threads" items={results.threads} />
            <SearchSection title="Posts" items={results.posts} />
        </div>
    );
}


function SearchSection({ title, items }) {
    if (!items?.length) return null;

    return (
        <>
            <div className="search-section-title">{title}</div>
            {items.map(item => (
                <SearchRow key={item.id} item={item} />
            ))}
        </>
    );
}


function SearchRow({ item }) {
    return (
        <a href={item.url} className="search-row">
            <div className="left">
                <div className="title">{item.title}</div>

                {item.subtitle && (
                    <div className="subtitle">{item.subtitle}</div>
                )}
            </div>

            <div className="right">
                {item.status && (
                    <span className={`status ${item.status}`}>
            {item.status}
          </span>
                )}
            </div>
        </a>
    );
}
